INSERT INTO website_config (key, value) VALUES ('general', '{"copyText":"© 2025 HOBA - Hiệp hội Kinh doanh Khí hóa lỏng TP.HCM. All rights reserved.","facebookUrl":"https://facebook.com/hobagroup","contactEmail":"info@hoba.vn","contactPhone":"028 3831 66710","registrationOpen":true,"maintenanceMode":true,"mapEmbedUrl":"<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d20832.12735789344!2d106.75810108202424!3d10.925482043130197!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3174d9ac15555555%3A0x3e0514c5b1212bfb!2zQ8O0bmcgdHkgVE5ISCBMb25nIFRodeG6rW4!5e1!3m2!1svi!2s!4v1780392623240!5m2!1svi!2s\" width=\"600\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"></iframe>","logoTitle":"HOBA LPG","logoSubtitle":"HCMC LPG Business Association","siteName":"HOBA LPG - Hiệp hội Kinh doanh Khí hóa lỏng TP.HCM","menuItems":[{"label":"Trang chủ","path":"/","children":[]},{"label":"Giới thiệu","path":"/gioi-thieu","children":[{"label":"Giới thiệu chung","path":"/gioi-thieu"},{"label":"Sơ đồ tổ chức","path":"/gioi-thieu#co-cau"},{"label":"Ban Chấp hành","path":"/ban-chap-hanh"},{"label":"Ban Thường vụ","path":"/ban-thuong-vu"},{"label":"Ban Kiểm tra","path":"/ban-kiem-tra"}]},{"label":"Hội viên","path":"/hoi-vien","children":[{"label":"Danh sách Hội viên","path":"/hoi-vien"},{"label":"Danh sách Chi hội","path":"/chi-hoi"},{"label":"Đăng ký Hội viên","path":"/dang-ky"}]},{"label":"Tin tức","path":"/tin-tuc","children":[]},{"label":"Sự kiện","path":"/su-kien","children":[]},{"label":"Văn bản","path":"/van-ban","children":[]},{"label":"Liên hệ","path":"/lien-he","children":[]}]}') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO website_config (key, value) VALUES ('aboutpage', '{"overview":"Hiệp hội Gas đô thị và Công nghiệp TP.HCM (HOBA) là tổ chức xã hội – nghề nghiệp tự nguyện của các doanh nghiệp hoạt động trong lĩnh vực sản xuất, kinh doanh, kinh doanh LPG và các sản phẩm, dịch vụ liên quan trên địa bàn Thành phố Hồ Chí Minh.","milestones":[{"id":"m1","date":"12/4/2025","title":"Hiệp hội Kinh doanh khí hóa lỏng (gas) tỉnh Bình Dương","desc":"Mốc thời gian thành lập đầu tiên."},{"id":"m2","date":"Tháng 11","title":"HIỆP HỘI KHÍ HÓA LỎNG THÀNH PHỐ HỒ CHÍ MINH","desc":"Mốc thời gian đổi tên chính thức."},{"id":"1780368272979","date":"2026","title":"Cột mốc mới","desc":"Chi tiết cột mốc hoạt động."},{"id":"1780368816475","date":"2027","title":"Cột mốc mới","desc":"Chi tiết cột mốc hoạt động.","icon":"flag"}],"values":[{"title":"Sứ mệnh","desc":"Kết nối – Đồng hành – Phát triển ngành LPG an toàn, bền vững và hiệu quả.","icon":"ads_click"},{"title":"Tầm nhìn","desc":"Trở thành tổ chức uy tín, đại diện cho cộng đồng doanh nghiệp LPG hàng đầu Việt Nam.","icon":"visibility"},{"title":"Giá trị cốt lõi","desc":"Minh bạch – Hợp tác – Chuyên nghiệp – Trách nhiệm cộng đồng.","icon":"diamond"}],"orgStructure":[{"title":"Ban chấp hành","desc":"Định hướng chiến lược, điều hành hoạt động của hiệp hội.","icon":"account_balance"},{"title":"Văn phòng hiệp hội","desc":"Tham mưu, quản lý, triển khai các hoạt động thường xuyên.","icon":"corporate_fare"},{"title":"Ban chuyên môn","desc":"Các tiểu ban: An toàn, Pháp lý, Đào tạo, Truyền thông.","icon":"settings_suggest"},{"title":"Hội viên doanh nghiệp","desc":"Các doanh nghiệp sản xuất, kinh doanh LPG trên địa bàn.","icon":"domain_verification"}],"heroImage":"https://lh3.googleusercontent.com/aida-public/AB6AXuCeZY8qdtczKmDT8VWnqLO1d2HQnkLJzPIAfexewwIjyrQK8F7-4mBaOrm4ZgQC3M-Ds7uNERwunFsK0tdzC_FNnhKGj3MDNQGdMmsGYiu3P88aKaxZ1ef_ZLyAz8WHtV_9OVzgd3cqoYhJAmqCGevUYZzhz9TnTOXDvZN5-Q-Va8Pm7y0BEtl2KMdZbYGKcuqlQ91wD8LWNDUb4p6WIxArZwc7p5TahTv0JMoEPbkCDBfB6xf8pe3cgmU-vGVEAza1fjGbgfB3Y3I","overviewImage":"https://lh3.googleusercontent.com/aida-public/AB6AXuA81hf5thmvBeYX2uBrxECeHNkAaZYnQEa5EMiRa7lwAzBGz3sI199whSRpFljMrgqBb13QPBj8m2g4cvIOwwp2C1Stt0_xzB4gl1vg4cKslAmhHN-WsTrN8xPZPkENHCkFPXncKXPnko9exmy70Q0joojrdU-7ZfGs_f95dk2mfS5sgzOhe4jST1ZHwBUmt9pUzlRmUl0bdhBlQnUA2yMAuFINhU4E_Wljat6wjQkLcFnrOtFAgI_ncw2i-VOpMpdtKxbP7sgqEhw"}') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO website_config (key, value) VALUES ('homepage', '{"headline":"An toàn năng lượng - Phát triển bền vững","subtext":"Hiệp hội HoBa hướng tới tiêu chuẩn an toàn quốc tế.","sections":[{"id":"hero","name":"1. Hero Banner","visible":true},{"id":"services","name":"3. Lĩnh vực hoạt động","visible":true},{"id":"news","name":"2. News & Events","visible":true},{"id":"stats","name":"4. Statistics Counter","visible":false},{"id":"members","name":"5. Hội viên tiêu biểu","visible":true}],"features":[{"id":"f1","title":"Tiêu chuẩn an toàn","icon":"verified_user","desc":"Xây dựng và ban hành các quy chuẩn kỹ thuật về an toàn LPG."},{"id":"f2","title":"Đào tạo nhân lực","icon":"school","desc":"Tổ chức các khóa huấn luyện nghiệp vụ cho cán bộ trong ngành."},{"id":"1780283310992","title":"Kết Nối","icon":"verified_user","desc":"Kết nối ngoài lĩnh vực"},{"id":"1780283346871","title":"Bảo vệ Cộng Đồng","icon":"verified_user","desc":"Bảo vệ giá trị thương hiệu và Gas lậu trên mọi mặt trận"}],"heroImage":"https://lh3.googleusercontent.com/aida-public/AB6AXuC981IWi1G9KO6TlBAeTvoEdHnU475mZUvpzKUy14ifBcHuc4b2zuDgHQNPQ2pPa1hNnCLFGrjwaaqqGhFcVpcCxdIlQZV1p_Vb6d2wfxy59lin66jklDgq9NGYjR4dSi5aUJ7vP7rQGNc70B9WC-g9cGfWoyIgi8SpKmbuwy2b4E7XrzpBKz9l2Gyr2B2cvva27oEuWW85ETPFGIk24eGr6JkgaTYZVPHxuaRxATS-URlM6yT-Jnu0VnYiPfUXGOeqtIJtDpOw4a0","stats":[{"value":"60+","label":"Hội viên liên kết","icon":"groups"},{"value":"2+","label":"Năm hoạt động","icon":"workspace_premium"},{"value":"100+","label":"Kết nối tạo giá trị","icon":"school"},{"value":"10+","label":"Đối tác chiến lược","icon":"handshake"}],"coreServices":[{"title":"Kết nối doanh nghiệp","desc":"Mở rộng mạng lưới hợp tác, chia sẻ nguồn lực và tạo dựng các mối quan hệ kinh doanh chiến lược.","icon":"handshake","bgIcon":"diversity_3"},{"title":"Phân tích thị trường","desc":"Cung cấp báo cáo phân tích giá gas quốc tế, xu hướng tiêu dùng và biến động chính sách.","icon":"trending_up","bgIcon":"query_stats"},{"title":"Tư vấn pháp lý","desc":"Tư vấn và phổ biến các thông tư, quy định mới liên quan đến kinh doanh và an toàn khí hóa lỏng.","icon":"gavel","bgIcon":"balance"},{"title":"Đào tạo an toàn","desc":"Huấn luyện kỹ thuật, an toàn PCCC và quản lý rủi ro cho đội ngũ kỹ thuật viên trạm chiết nạp.","icon":"engineering","bgIcon":"school"},{"title":"Sự kiện & Hội thảo","desc":"Tổ chức các diễn đàn xúc tiến đầu tư và các buổi giao lưu ngành gas toàn quốc định kỳ.","icon":"groups_2","bgIcon":"event_seat"},{"title":"Hỗ trợ thủ tục","desc":"Tư vấn tháo gỡ vướng mắc về giấy phép và các thủ tục hành chính chuyên ngành năng lượng.","icon":"support_agent","bgIcon":"health_and_safety"}],"aboutTitle":"HIỆP HỘI KINH DOANH KHÍ HÓA LỎNG TP.HCM","aboutDesc":"HOBA là tổ chức xã hội – nghề nghiệp hội tụ các tinh hoa doanh nghiệp trong lĩnh vực LPG. Chúng tôi không chỉ là người đại diện pháp lý mà còn là nền tảng kết nối chiến lược, định hướng tiêu chuẩn an toàn cao nhất cho thị trường.","aboutImage":"https://lh3.googleusercontent.com/aida-public/AB6AXuBqie_pC3yMckoN2RbI--_RMwqaycD-sE8uNjKGm1FYP4SuDo4Bk_DoW8FUfF5HZBFyE2S74tiVXbJg9vHPDi60KxsMnl9tK_9RvcEVcILr8J8xd5TjTAruNuf3db-Gwy4Kb5FvIKtk35uWDdSOWlVsvITLSEFRwOtiZ4946ZRBlOrGlV9a4b40tsttuO67wPg5hKgKI3TVz1c8T_rONHoB_-tlV2x6YjTCExPwRqjjfG4Qm2IJnhUprj3rNJr25ksTMbc-7ceVtUA"}') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO website_config (key, value) VALUES ('memberspage', '{"headline":"Danh sách Hội viên Hiệp hội","subtext":"Nơi quy tụ các doanh nghiệp hàng đầu trong lĩnh vực Khí dầu mỏ hóa lỏng (LPG) tại Việt Nam, cam kết vì sự phát triển bền vững và an toàn năng lượng.","heroImage":"https://lh3.googleusercontent.com/aida-public/AB6AXuBTP1VwRhiXz7IslKk8lyrl_NZjrM0MYtWMLyaBrXhEX2DRZ9wIHjlle-92NsUhnYmQwD4yTguPqimc2ewjOD30dygdkHwHt7s9NXsMPSnzWvTyHO_1lM5j2kM_9BcFoN9m67VEakH0ReGkHCz2mX7R0kfbHFSyqSNrqYFcUsBMK0sm4skbO_7LO2Qs237Mbc_zUrwOxQ0lEHdDE-3w74hK182bzXXoJ9Nz4No0EMfJPJZ14JUTiBDxNw-onJOCwry6C0bNPzf9aJY","sections":[{"id":"hero","name":"1. Banner chính","visible":true},{"id":"tabs","name":"2. Danh sách Hội viên","visible":true},{"id":"stats","name":"3. Thống kê tổng hợp","visible":true},{"id":"benefits","name":"4. Quyền lợi hội viên","visible":true},{"id":"steps","name":"5. Quy trình gia nhập","visible":true}],"stats":[{"value":"64","label":"Doanh nghiệp Hội viên","icon":"groups"},{"value":"63","label":"Tỉnh thành phủ sóng","icon":"location_on"},{"value":"100%","label":"Cam kết an toàn","icon":"verified"},{"value":"2025","label":"Năm thành lập","icon":"calendar_today"}],"benefits":[{"title":"Kết nối doanh nghiệp","desc":"Kết nối với cộng đồng hội viên và đối tác chiến lược trong ngành LPG toàn quốc.","icon":"hub"},{"title":"Cập nhật chính sách","desc":"Cập nhật nhanh chóng chính sách, quy định pháp luật mới nhất liên quan đến khí hóa lỏng.","icon":"update"},{"title":"Đào tạo chuyên môn","desc":"Tham gia các khóa đào tạo, hội thảo chuyên đề kỹ thuật và quản lý chất lượng cao.","icon":"school"},{"title":"Xúc tiến hợp tác","desc":"Cơ hội hợp tác, mở rộng thị trường và phát triển các liên kết kinh doanh bền vững.","icon":"rocket_launch"},{"title":"Hỗ trợ pháp lý","desc":"Tư vấn, hỗ trợ pháp lý và bảo vệ quyền lợi hợp pháp của hội viên trong kinh doanh.","icon":"gavel"},{"title":"Nâng cao uy tín","desc":"Tăng uy tín và hình ảnh thương hiệu thông qua các hoạt động cộng đồng của Hiệp hội.","icon":"verified"}],"steps":[{"title":"Đăng ký hồ sơ","desc":"Doanh nghiệp điền thông tin và nộp hồ sơ đăng ký online.","icon":"description","step":"01"},{"title":"Xét duyệt","desc":"Ban chấp hành xem xét, thẩm định và phê duyệt hồ sơ.","icon":"fact_check","step":"02"},{"title":"Kết nối - Kích hoạt","desc":"Kích hoạt quyền hội viên và bắt đầu các hoạt động kết nối.","icon":"handshake","step":"03"},{"title":"Tham gia cộng đồng","desc":"Hưởng đầy đủ quyền lợi và tham gia các sự kiện của Hiệp hội.","icon":"celebration","step":"04"}],"associationRoles":["Chủ tịch","Phó Chủ tịch","Ban kiểm tra","Ủy viên Ban Thường vụ","Ủy viên Ban Chấp hành","Hội viên chính thức","Hội viên liên kết"]}') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO website_config (key, value) VALUES ('registerpage', '{"title":"Đăng Ký Hội Viên Doanh Nghiệp","subtitle":"Gia nhập cộng đồng LPG Việt Nam để nâng cao tiêu chuẩn an toàn và kết nối cơ hội kinh doanh bền vững.","hotline":"09090909","step1Label":"Doanh nghiệp","step2Label":"Người đại diện","step3Label":"Hồ sơ pháp lý","step4Label":"Xác nhận","agreementText":"Tôi cam kết các thông tin cung cấp là chính xác và hoàn toàn chịu trách nhiệm trước pháp luật cũng như các quy định của Hội."}') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO website_config (key, value) VALUES ('hoba_website_committee_ban-chap-hanh', '{"term":"NHIỆM KỲ 2025 - 2029","title":"Ban Chấp hành Hiệp hội HOBA LPG","subtitle":"Lãnh đạo và định hướng phát triển ngành khí hóa lỏng (LPG) hướng tới tiêu chuẩn an toàn, minh bạch và bền vững.","chairman":{"name":"Đinh Văn Hiểu","role":"Chủ tịch Hiệp hội","company":"Công ty TNHH Long Thuận","avatarUrl":"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&q=80&w=256","memberId":"mem-bd-1","isVerified":true},"viceChairmen":[{"name":"Trần Đức Nhã","role":"Phó Chủ tịch Hiệp hội","company":"Công ty TNHH Phước Thiên","avatarUrl":"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&q=80&w=256","memberId":"mem-bd-2"},{"name":"Lê Khắc Huy","role":"Phó Chủ tịch Hiệp hội","company":"Công ty TNHH MTV Ga Việt","avatarUrl":"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&q=80&w=256","memberId":"mem-bd-4"},{"name":"Phan Thị Huệ","role":"Phó Chủ tịch Hiệp hội","company":"Công ty cổ phần Hoàng Gia Việt Luxen’s Care","avatarUrl":"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&q=80&w=256","memberId":"mem-bd-5"}],"members":[{"name":"Phạm Trung Kiên","role":"Ủy viên Ban Chấp hành","company":"Cổ phần khí hóa lỏng Hoàng Anh","avatarUrl":"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&q=80&w=256","memberId":"mem-bd-3"},{"name":"Đinh Huy Long","role":"Ủy viên Ban Chấp hành","company":"công ty cổ phần Ubergas.","avatarUrl":"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&q=80&w=256","memberId":"mem-bd-6"},{"name":"Nguyễn Văn Chính","role":"Ủy viên Ban Chấp hành","company":"Chủ hộ kinh doanh Phạm Thị Ngát","avatarUrl":"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&q=80&w=256","memberId":"mem-bd-7"},{"name":"Nguyễn Thị Bích","role":"Ủy viên Ban Chấp hành","company":"Chủ Cử