INSERT INTO website_config (key, value) VALUES ('hoba_website_committee_ban-kiem-tra', '{"term":"NHIỆM KỲ 2025 - 2029","title":"Ban Kiểm tra Hiệp hội HOBA LPG","subtitle":"Giám sát hoạt động của Hiệp hội, kiểm tra việc chấp hành điều lệ và quản lý tài chính công khai, minh bạch.","chairman":{"name":"Bùi An Bình","role":"Trưởng Ban Kiểm tra","company":"Chủ Cửa hàng Gas Thanh Dương","avatarUrl":"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&q=80&w=256","isVerified":true,"memberId":"mem-bd-22"},"viceChairmen":[{"name":"Nguyễn Văn Sơn","role":"Phó Trưởng Ban Kiểm tra","company":"Chủ Cửa hàng gas Quỳnh Bảo","avatarUrl":"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&q=80&w=256","memberId":"mem-bd-32"}],"members":[],"showChairman":true,"showViceChairmen":true,"showMembers":true}') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;
